CREATE TABLE IF NOT EXISTS algeria_cities (
    id INT PRIMARY KEY,
    commune_name VARCHAR(255),
    commune_name_fr VARCHAR(255),
    daira_name VARCHAR(255),
    daira_name_fr VARCHAR(255),
    wilaya_code INT,
    wilaya_name VARCHAR(255),
    wilaya_name_fr VARCHAR(255),
    code_commune INT,
    lat DECIMAL(10, 8),
    lon DECIMAL(11, 8)
);

